import{_ as e}from"./chunks/board.DNHnF88t.js";import{_ as r,o as a,c as o,a2 as n}from"./chunks/framework.ChXBHUFc.js";const i="/triki/img/axes.jpg",u=JSON.parse('{"title":"Hardware","description":"","frontmatter":{},"headers":[],"relativePath":"guide/hardware.md","filePath":"guide/hardware.md","lastUpdated":1782668631000}'),d={name:"guide/hardware.md"};function s(h,t,c,g,l,p){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="hardware" tabindex="-1">Hardware <a class="header-anchor" href="#hardware" aria-label="Permalink to &quot;Hardware&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Component</th><th>Part</th><th>Role</th></tr></thead><tbody><tr><td>MCU</td><td><strong>nRF52810-QCxx</strong> (QFN, marking <code>N52810 QDAAE0</code>)</td><td>BLE SoC, Cortex-M4</td></tr><tr><td>IMU</td><td><strong>LSM6DSL</strong></td><td>3-axis accel + gyro (motion input)</td></tr><tr><td>External flash</td><td><strong>Macronix MX25R8035F</strong> (SPI NOR, 8 Mbit / 1 MB)</td><td>external storage</td></tr><tr><td>Clock</td><td>32.000 MHz crystal</td><td></td></tr><tr><td>Other</td><td>BLE antenna, LED, button</td><td></td></tr></tbody></table><figure style="margin:1rem 0;max-width:480px;"><img src="'+e+'" alt="Triki board — nRF52810"><figcaption>Board — Żabka &quot;Z&quot; logo, nRF52810</figcaption></figure><p>The <strong>LSM6DSL</strong> accelerometer/gyroscope is the part this project cares about — see <a href="./imu-streaming">IMU streaming</a> for reading it live over BLE.</p><h2 id="imu-axis-orientation" tabindex="-1">IMU axis orientation <a class="header-anchor" href="#imu-axis-orientation" aria-label="Permalink to &quot;IMU axis orientation&quot;">​</a></h2><p>The IMU axes were mapped empirically — holding the token still in each face-up / edge-up pose and reading which accelerometer axis settles at ±1 g. Reference frame: look at the <strong>PCB face</strong> (the green board with the <strong>Ż</strong> logo) held upright; <strong>+Z</strong> points out of the PCB face, toward you.</p><p><img src="'+i+'" alt="Triki IMU axes — looking at the PCB face"></p><table tabindex="0"><thead><tr><th>Axis</th><th>Points toward (PCB face up, Ż upright)</th></tr></thead><tbody><tr><td><strong>+Z</strong></td><td>out of the PCB face (Ż side)</td></tr><tr><td><strong>−Z</strong></td><td>out of the cap face (metal crown / &quot;T&quot; logo)</td></tr><tr><td><strong>−Y</strong></td><td>top of the Ż (12 o&#39;clock)</td></tr><tr><td><strong>+Y</strong></td><td>bottom of the Ż (6 o&#39;clock)</td></tr><tr><td><strong>−X</strong></td><td>right of the Ż (3 o&#39;clock)</td></tr><tr><td><strong>+X</strong></td><td>left of the Ż (9 o&#39;clock)</td></tr></tbody></table><p>The accelerometer axes form a <strong>right-handed</strong> triad (X × Y = +Z), matching the LSM6DSL convention.</p><p>Measured (token still, one axis up at a time): PCB face up → Z ≈ +1.0 g; cap face up → Z ≈ −1.0 g; top of Ż up → Y ≈ −1.0 g; right of Ż up → X ≈ −1.0 g; left of Ż up → X ≈ +1.0 g. Per-axis magnitudes vary by a few percent (uncalibrated MEMS offset/scale).</p><h3 id="what-the-accelerometer-vector-means" tabindex="-1">What the accelerometer vector means <a class="header-anchor" href="#what-the-accelerometer-vector-means" aria-label="Permalink to &quot;What the accelerometer vector means&quot;">​</a></h3><p>The accelerometer measures <strong>specific force</strong> — the support/reaction force on the sensor — <strong>not</strong> gravity directly. At rest it reads the reaction that holds the token out of free fall, so the vector points <strong>up, away from Earth</strong>, with magnitude ≈ 1 g: the axis facing the sky reads <strong>+1 g</strong>. The direction <em>toward</em> Earth is therefore <strong>−accel</strong> while the token is still. In free fall it would read ≈ 0. During motion, linear acceleration adds to the gravity component — which is why orientation is recovered with a fusion filter (Madgwick) rather than by trusting raw accel as &quot;down&quot;.</p>',12)])])}const w=r(d,[["render",s]]);export{u as __pageData,w as default};
